external_knowledge:
; A top-level building is a building that has no project manager ID, indicating that it is the highest level in the building hierarchy; 
; Cumulative load refers to the total load of a particular load type, calculated by summing up the loads of that type; 
; The versions of buildings, thermal zones, and heating/cooling types refer to the different versions or updates of these entities; 
; Project managers are users who are responsible for managing buildings and thermal zones.

sql:
SELECT type_id, COUNT(*) AS version_count
FROM heating_cooling_types_versions
GROUP BY type_id;

SELECT load_value
FROM design_loads
WHERE load_id = 0;

SELECT COUNT(load_id) AS total_design_loads, AVG(load_value) AS average_load_value
FROM design_loads
WHERE zone_id = 1;

SELECT zone_name, zone_area
FROM thermal_zones
WHERE zone_area = (SELECT MAX(zone_area) FROM thermal_zones);

SELECT type_name, AVG(operational_cost) AS avg_operational_cost
FROM heating_cooling_types
GROUP BY type_name;

SELECT zone_area, zone_volume
FROM thermal_zones
WHERE zone_area > 100 AND zone_volume > 1000;

SELECT SUM(flow_value) AS total_flow, AVG(flow_value) AS average_flow
FROM air_flows
WHERE zone_id = 1;

external_knowledge:
; Thermal zones refer to areas in a building that are designed to maintain a uniform temperature; 
; Zone order may imply a sequence or priority of thermal zones within a building; 
; Various statistics help in analyzing and optimizing the thermal zones' performance and energy efficiency.
